mapper.select:
${pagingTop}
	SELECT
		HOMEPAGE_ID, IMG_IDX, TITLE, IMG_FILE_NAME, REAL_FILE_NAME, FILE_EXTENSION, FILE_SIZE, USE_YN, PRINT_SEQ, TO_CHAR(ADD_DATE, 'yyyy-mm-dd hh24:mm') AS ADD_DATE, MAINIMG_LINK
	FROM
		CMS_MAIN_IMG
	WHERE HOMEPAGE_ID = #{homepage_id}

		AND	${search_type} LIKE '%'||#{search_text}||'%'

	ORDER BY
		PRINT_SEQ ASC, add_date DESC
${pagingBottom}

SELECT COUNT(*) FROM CMS_MAIN_IMG WHERE HOMEPAGE_ID = #{homepage_id}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY PRINT_SEQ ASC, add_date DESC

